import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.pipedrive.com/docs/api/v1";
const PLACEHOLDER_VALUE = "c0ffee5afe10ca1c0ffee5afe10ca1c0ffee5afe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Pipedrive API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:pipedrive",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const pipedriveFirewall = {",
    '  name: "pipedrive",',
    '  description: "Pipedrive",',
    "  placeholders: {",
    `    PIPEDRIVE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.pipedrive.com",',
    "      auth: {",
    "        headers: {",
    '          "x-api-token": "${{ secrets.PIPEDRIVE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Pipedrive firewall config...");
  const ts = generateTypeScript();
  writeOutput("pipedrive", ts, import.meta.dirname);
}
